@Override
    public void writeInt8(byte[] values) {
        if (values == null) {
            writeArrayNull();
            return;
        }

        int off = this.off;
        int size = values.length;
        int minCapacity = off + 6 + values.length * 2;
        byte[] bytes = this.bytes;
        if (minCapacity > bytes.length) {
            bytes = grow(minCapacity);
        }

        if (size <= ARRAY_FIX_LEN) {
            bytes[off++] = (byte) (BC_ARRAY_FIX_MIN + size);
        } else {
            bytes[off] = BC_ARRAY;
            off = JSONB.IO.writeInt32(bytes, off + 1, size);
        }

        for (int val : values) {
            if (val < BC_INT32_NUM_MIN || val > BC_INT32_NUM_MAX) {
                bytes[off++] = (byte) (BC_INT32_BYTE_ZERO + (val >> 8));
            }
            bytes[off++] = (byte) val;
        }
        this.off = off;
    }

public static Map<String, SubscriberStatus> listSubStatus(String ip) {
    Map<String, SubscriberStatus> status = new HashMap<>(100);

    // record here is non-null
    ClientRecord record = getClientRecord(ip);
    for (Map.Entry<String, String> entry : record.getGroupKey2md5Map().entrySet()) {
        String groupKey = entry.getKey();
        String clientMd5 = entry.getValue();
        long lastPollingTs = record.getGroupKey2pollingTsMap().get(groupKey);
        boolean isUpdate = ConfigCacheService.isUptodate(groupKey, clientMd5);

        status.put(groupKey,
            new SubscriberStatus(groupKey, isUpdate, clientMd5, lastPollingTs));
    }

    return status;
}

private Consumer<List<DatanodeInfoWithStorage>> createSecondaryNodeSorter() {
  Consumer<List<DatanodeInfoWithStorage>> secondarySort = null;
  if (readConsiderStorageType) {
    Comparator<DatanodeInfoWithStorage> comp =
        Comparator.comparing(DatanodeInfoWithStorage::getStorageType, (s1, s2) -> {
          if (s1 == null) {
            return (s2 == null) ? 0 : -1;
          } else if (s2 == null) {
            return 1;
          } else {
            return s1.compareTo(s2);
          }
        });
    secondarySort = list -> Collections.sort(list, comp);
  }
  if (readConsiderLoad) {
    Comparator<DatanodeInfoWithStorage> comp =
        Comparator.comparingInt(DatanodeInfo::getXceiverCount);
    secondarySort = list -> Collections.sort(list, comp);
  }
  return secondarySort;
}

@Override
    public DocComparator getDocComparator(LeafReader reader, int maxDoc) throws IOException {
      final NumericDocValues dvs = valuesProvider.get(reader);
      int[] values = new int[maxDoc];
      if (this.missingValue != null) {
        Arrays.fill(values, this.missingValue);
      }
      while (true) {
        int docID = dvs.nextDoc();
        if (docID == NO_MORE_DOCS) {
          break;
        }
        values[docID] = (int) dvs.longValue();
      }

      return (docID1, docID2) -> reverseMul * Integer.compare(values[docID1], values[docID2]);
    }

